class Solution:
    def minimumFlips(self, n):
        s = bin(n)[2:]
        L = len(s)
        pairs_mismatched = 0
        i, j = 0, L - 1
        while i < j:
            if s[i] != s[j]:
                pairs_mismatched += 1
            i += 1
            j -= 1
        return pairs_mismatched * 2

solutions.python:
class Solution:
    def minimumFlips(self, n):
        s = bin(n)[2:]
        t = s[::-1]
        return sum(1 for a, b in zip(s, t) if a != b)

